		/// --------------------------------<br/>
		/// The example below shows how to initialize the context using custom backend priorities and a custom configuration. In this hypothetical example, the program<br/>
		/// wants to prioritize ALSA over PulseAudio on Linux. They also want to avoid using the WinMM backend on Windows because it's latency is too high. They also<br/>
		/// want an error to be returned if no valid backend is available which they achieve by excluding the Null backend.<br/>
		/// For the configuration, the program wants to capture any log messages so they can, for example, route it to a log file and user interface.<br/>
		/// ```c<br/>
		/// ma_backend backends[] = {<br/>
		/// ma_backend_alsa,<br/>
		/// ma_backend_pulseaudio,<br/>
		/// ma_backend_wasapi,<br/>
		/// ma_backend_dsound<br/>
		/// };<br/>
		/// ma_log log;<br/>
		/// ma_log_init(<br/>
		/// &log<br/>
		/// );<br/>
		/// ma_log_register_callback(<br/>
		/// &log<br/>
		/// , ma_log_callback_init(my_log_callbac, pMyLogUserData));<br/>
		/// ma_context_config config = ma_context_config_init();<br/>
		/// config.pLog = <br/>
		/// &log;<br/>
		/// // Specify a custom log object in the config so any logs that are posted from ma_context_init() are captured.<br/>
		/// ma_context context;<br/>
		/// ma_result result = ma_context_init(backends, sizeof(backends)/sizeof(backends[0]), <br/>
		/// &config<br/>
		/// , <br/>
		/// &context<br/>
		/// );<br/>
		/// if (result != MA_SUCCESS) {<br/>
		/// // Error.<br/>
		/// if (result == MA_NO_BACKEND) {<br/>
		/// // Couldn't find an appropriate backend.<br/>
		/// }<br/>
		/// }<br/>
		/// // You could also attach a log callback post-initialization:<br/>
		/// ma_log_register_callback(ma_context_get_log(<br/>
		/// &context<br/>
		/// ), ma_log_callback_init(my_log_callback, pMyLogUserData));<br/>
		/// ```<br/>
		/// See Also<br/>
		/// --------<br/>
		/// ma_context_config_init()<br/>
		/// ma_context_uninit()<br/>
		/// </summary>
		public static MaResult ContextInit(MaBackend* backends, uint backendCount, in MaContextConfig pConfig, MaContextPtr pContext)
		{
			fixed (MaContextConfig* ppConfig = &pConfig)
			{
				MaResult ret = ContextInitNative(backends, backendCount, (MaContextConfig*)ppConfig, (MaContext*)pContext);
				return ret;
			}
		}

